#include <stdio.h>
#include <stdlib.h>

static long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        while (Q--) {
            long long u, v; scanf("%lld %lld", &u, &v);
            if (u == v) {
                printf("0\n");
                continue;
            }
            long long a = u < v ? u : v;
            long long b = u < v ? v : u;
            if (b % a == 0) {
                printf("%lld\n", b / a);
            } else {
                long long g = gcd_ll(u, v);
                printf("%lld\n", (u + v) / g);
            }
        }
    }
    return 0;
}

