import sys

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        Q = int(next(it))
        for __ in range(Q):
            u = int(next(it))
            v = int(next(it))
            if u == v:
                out_lines.append('0')
                continue
            a, b = (u, v) if u < v else (v, u)
            if b % a == 0:
                out_lines.append(str(b // a))
            else:
                g = gcd(u, v)
                out_lines.append(str((u + v) // g))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

